import type {
  ExcalidrawElement,
  NonDeleted,
} from '@excalidraw/excalidraw/element/types';
import type { AppState, BinaryFiles } from '@excalidraw/excalidraw/types';
import type { JSX } from 'react';

import { exportToSvg } from '@excalidraw/excalidraw';
import * as React from 'react';
import { useEffect, useState } from 'react';

import { registerExcalidrawFontFamilies } from '../../utils/excalidrawFontRegistration';
import type { ExtraFontFamilyOption } from '../../utils/fontFamilyOptions';

type ImageType = 'svg' | 'canvas';

type Dimension = 'inherit' | number;

const EMPTY_EXTRA_FONT_FAMILIES: ReadonlyArray<ExtraFontFamilyOption> = [];

type Props = {
  /**
   * Configures the export setting for SVG/Canvas
   */
  appState: AppState;
  /**
   * The css class applied to image to be rendered
   */
  className?: string;
  /**
   * The Excalidraw elements to be rendered as an image
   */
  elements: NonDeleted<ExcalidrawElement>[];
  /**
   * The Excalidraw files associated with the elements
   */
  files: BinaryFiles;
  /**
   * Extra editor font families used by text elements in the scene
   */
  extraFontFamilies?: ReadonlyArray<ExtraFontFamilyOption>;
  /**
   * The height of the image to be rendered
   */
  height?: Dimension;
  /**
   * The ref object to be used to render the image
   */
  imageContainerRef: React.RefObject<HTMLDivElement | null>;
  /**
   * The type of image to be rendered
   */
  imageType?: ImageType;
  /**
   * The css class applied to the root element of this component
   */
  rootClassName?: string | null;
  /**
   * The width of the image to be rendered
   */
  width?: Dimension;
};

const DEFAULT_EXCALIDRAW_CANVAS_BACKGROUND_COLORS = new Set([
  '#fff',
  '#ffffff',
  'rgb(255, 255, 255)',
  'white',
]);

function isDefaultCanvasBackgroundColor(color: unknown): boolean {
  return (
    typeof color !== 'string' ||
    color.trim() === '' ||
    DEFAULT_EXCALIDRAW_CANVAS_BACKGROUND_COLORS.has(color.trim().toLowerCase())
  );
}

function getPreviewAppState(appState: AppState): AppState {
  const isDarkExport =
    appState.exportWithDarkMode === true || appState.theme === 'dark';

  if (
    appState.exportBackground !== false &&
    isDefaultCanvasBackgroundColor(appState.viewBackgroundColor)
  ) {
    return {
      ...appState,
      exportBackground: false,
      ...(isDarkExport ? { exportWithDarkMode: true } : {}),
    };
  }

  return appState;
}

// exportToSvg has fonts from excalidraw.com
// We don't want them to be used in open source
const removeStyleFromSvg_HACK = (svg: SVGElement) => {
  const styleTag = svg?.firstElementChild?.firstElementChild;

  // Generated SVG is getting double-sized by height and width attributes
  // We want to match the real size of the SVG element
  const viewBox = svg.getAttribute('viewBox');
  if (viewBox != null) {
    const viewBoxDimensions = viewBox.split(' ');
    svg.setAttribute('width', viewBoxDimensions[2]);
    svg.setAttribute('height', viewBoxDimensions[3]);
  }

  if (styleTag && styleTag.tagName === 'style') {
    styleTag.remove();
  }
};

/**
 * @explorer-desc
 * A component for rendering Excalidraw elements as a static image
 */
export default function ExcalidrawImage({
  elements,
  files,
  extraFontFamilies = EMPTY_EXTRA_FONT_FAMILIES,
  imageContainerRef,
  appState,
  rootClassName = null,
  width = 'inherit',
  height = 'inherit',
}: Props): JSX.Element {
  const [Svg, setSvg] = useState<SVGElement | null>(null);

  useEffect(() => {
    let isActive = true;

    const setContent = async () => {
      await registerExcalidrawFontFamilies(extraFontFamilies);
      const svg: SVGElement = await exportToSvg({
        appState: getPreviewAppState(appState),
        elements,
        files,
      });
      removeStyleFromSvg_HACK(svg);

      svg.setAttribute('width', '100%');
      svg.setAttribute('height', '100%');
      svg.setAttribute('display', 'block');

      if (isActive) {
        setSvg(svg);
      }
    };
    void setContent().catch((error: unknown) => {
      console.error(error);
    });

    return () => {
      isActive = false;
    };
  }, [elements, files, appState, extraFontFamilies]);

  const containerStyle: React.CSSProperties = {};
  if (width !== 'inherit') {
    containerStyle.width = `${width}px`;
  }
  if (height !== 'inherit') {
    containerStyle.height = `${height}px`;
  }

  return (
    <div
      ref={(node) => {
        if (node) {
          if (imageContainerRef) {
            imageContainerRef.current = node;
          }
        }
      }}
      className={rootClassName ?? ''}
      style={containerStyle}
      dangerouslySetInnerHTML={{ __html: Svg?.outerHTML ?? '' }}
    />
  );
}
